-- Project Harborlight Phase 1: additive community catalog foundation.
CREATE TABLE "CommunityProfile" ("id" TEXT NOT NULL PRIMARY KEY, "identityKey" TEXT NOT NULL, "identityKind" TEXT NOT NULL DEFAULT 'PLAYER_PROFILE', "playerProfileId" TEXT, "normalizedHandle" TEXT NOT NULL, "handle" TEXT NOT NULL, "displayName" TEXT NOT NULL, "biography" TEXT, "visibility" TEXT NOT NULL DEFAULT 'COMMUNITY', "creatorStatus" TEXT NOT NULL DEFAULT 'ACTIVE', "moderationStatus" TEXT NOT NULL DEFAULT 'ACTIVE', "verificationStatus" TEXT NOT NULL DEFAULT 'UNVERIFIED', "supportedLanguages" TEXT NOT NULL DEFAULT '[]', "socialLinks" TEXT NOT NULL DEFAULT '[]', "lastPublishedAt" DATETIME, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL);
CREATE UNIQUE INDEX "CommunityProfile_identityKey_key" ON "CommunityProfile"("identityKey"); CREATE UNIQUE INDEX "CommunityProfile_playerProfileId_key" ON "CommunityProfile"("playerProfileId"); CREATE UNIQUE INDEX "CommunityProfile_normalizedHandle_key" ON "CommunityProfile"("normalizedHandle"); CREATE INDEX "CommunityProfile_moderationStatus_visibility_idx" ON "CommunityProfile"("moderationStatus", "visibility");
CREATE TABLE "CommunityListing" ("id" TEXT NOT NULL PRIMARY KEY, "slug" TEXT NOT NULL, "itemType" TEXT NOT NULL, "ownerProfileId" TEXT NOT NULL, "title" TEXT NOT NULL, "shortDescription" TEXT, "longDescription" TEXT, "visibility" TEXT NOT NULL DEFAULT 'PRIVATE', "publicationStatus" TEXT NOT NULL DEFAULT 'DRAFT', "moderationStatus" TEXT NOT NULL DEFAULT 'ACTIVE', "spoilerLevel" TEXT NOT NULL DEFAULT 'PREVIEW_SAFE', "locationClass" TEXT NOT NULL DEFAULT 'FICTIONAL', "primaryCategory" TEXT, "tags" TEXT NOT NULL DEFAULT '[]', "contentWarnings" TEXT NOT NULL DEFAULT '[]', "currentReleaseId" TEXT, "publishedAt" DATETIME, "archivedAt" DATETIME, "removedAt" DATETIME, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL);
CREATE UNIQUE INDEX "CommunityListing_slug_key" ON "CommunityListing"("slug"); CREATE UNIQUE INDEX "CommunityListing_currentReleaseId_key" ON "CommunityListing"("currentReleaseId"); CREATE INDEX "CommunityListing_ownerProfileId_updatedAt_idx" ON "CommunityListing"("ownerProfileId", "updatedAt"); CREATE INDEX "CommunityListing_publicationStatus_visibility_idx" ON "CommunityListing"("publicationStatus", "visibility");
CREATE TABLE "CommunityRelease" ("id" TEXT NOT NULL PRIMARY KEY, "listingId" TEXT NOT NULL, "semanticVersion" TEXT NOT NULL, "manifestSchemaVersion" INTEGER NOT NULL DEFAULT 1, "minimumPlatformVersion" TEXT, "sourcePublishedTaleVersionId" TEXT, "manifest" TEXT NOT NULL, "manifestChecksum" TEXT NOT NULL, "packageChecksum" TEXT, "releaseNotes" TEXT, "compatibility" TEXT NOT NULL DEFAULT '{}', "licenseSnapshot" TEXT NOT NULL, "attributionSnapshot" TEXT NOT NULL DEFAULT '[]', "spoilerSnapshot" TEXT NOT NULL DEFAULT '{}', "moderationStatus" TEXT NOT NULL DEFAULT 'ACTIVE', "publishedByProfileId" TEXT NOT NULL, "publishedAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "deprecatedAt" DATETIME, "replacementReleaseId" TEXT, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX "CommunityRelease_listingId_semanticVersion_key" ON "CommunityRelease"("listingId", "semanticVersion"); CREATE INDEX "CommunityRelease_listingId_publishedAt_idx" ON "CommunityRelease"("listingId", "publishedAt"); CREATE INDEX "CommunityRelease_sourcePublishedTaleVersionId_idx" ON "CommunityRelease"("sourcePublishedTaleVersionId");
CREATE TABLE "CommunityReleaseAttribution" ("id" TEXT NOT NULL PRIMARY KEY, "releaseId" TEXT NOT NULL, "creditedProfileId" TEXT, "creditedDisplayName" TEXT NOT NULL, "contributionType" TEXT NOT NULL, "sourceUrl" TEXT, "requiredCreditText" TEXT, "licenseReference" TEXT, "sortOrder" INTEGER NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP); CREATE INDEX "CommunityReleaseAttribution_releaseId_sortOrder_idx" ON "CommunityReleaseAttribution"("releaseId", "sortOrder");
CREATE TABLE "CommunityOwnershipDeclaration" ("id" TEXT NOT NULL PRIMARY KEY, "listingId" TEXT NOT NULL, "releaseId" TEXT, "declarantProfileId" TEXT NOT NULL, "declarationVersion" INTEGER NOT NULL, "acceptedStatements" TEXT NOT NULL, "evidenceReferences" TEXT NOT NULL DEFAULT '[]', "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP); CREATE INDEX "CommunityOwnershipDeclaration_listingId_releaseId_idx" ON "CommunityOwnershipDeclaration"("listingId", "releaseId");
CREATE TABLE "CommunityAssetReference" ("id" TEXT NOT NULL PRIMARY KEY, "ownerProfileId" TEXT NOT NULL, "releaseId" TEXT, "checksum" TEXT NOT NULL, "declaredMimeType" TEXT NOT NULL, "detectedMimeType" TEXT, "fileSize" INTEGER NOT NULL, "storageProvider" TEXT NOT NULL, "storageKey" TEXT NOT NULL, "visibility" TEXT NOT NULL DEFAULT 'PRIVATE', "scanStatus" TEXT NOT NULL DEFAULT 'SCAN_NOT_CONFIGURED', "processingStatus" TEXT NOT NULL DEFAULT 'UPLOADED', "accessibility" TEXT NOT NULL DEFAULT '{}', "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL, "removedAt" DATETIME); CREATE UNIQUE INDEX "CommunityAssetReference_storageKey_key" ON "CommunityAssetReference"("storageKey"); CREATE UNIQUE INDEX "CommunityAssetReference_ownerProfileId_checksum_key" ON "CommunityAssetReference"("ownerProfileId", "checksum"); CREATE INDEX "CommunityAssetReference_releaseId_visibility_idx" ON "CommunityAssetReference"("releaseId", "visibility");
CREATE TABLE "CommunityOutboxEvent" ("id" TEXT NOT NULL PRIMARY KEY, "eventType" TEXT NOT NULL, "aggregateType" TEXT NOT NULL, "aggregateId" TEXT NOT NULL, "payloadVersion" INTEGER NOT NULL DEFAULT 1, "payload" TEXT NOT NULL, "idempotencyKey" TEXT NOT NULL, "availableAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "claimedAt" DATETIME, "processedAt" DATETIME, "attemptCount" INTEGER NOT NULL DEFAULT 0, "terminalFailureAt" DATETIME, "failureCode" TEXT, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP); CREATE UNIQUE INDEX "CommunityOutboxEvent_idempotencyKey_key" ON "CommunityOutboxEvent"("idempotencyKey"); CREATE INDEX "CommunityOutboxEvent_processedAt_availableAt_idx" ON "CommunityOutboxEvent"("processedAt", "availableAt"); CREATE INDEX "CommunityOutboxEvent_aggregateType_aggregateId_createdAt_idx" ON "CommunityOutboxEvent"("aggregateType", "aggregateId", "createdAt");
CREATE TABLE "CommunityLicensePolicy" ("id" TEXT NOT NULL PRIMARY KEY, "key" TEXT NOT NULL, "displayName" TEXT NOT NULL, "policyVersion" INTEGER NOT NULL DEFAULT 1, "allowsPrivateUse" BOOLEAN NOT NULL DEFAULT true, "allowsPublicUse" BOOLEAN NOT NULL DEFAULT false, "allowsModification" BOOLEAN NOT NULL DEFAULT false, "allowsRedistribution" BOOLEAN NOT NULL DEFAULT false, "allowsCommercialUse" BOOLEAN NOT NULL DEFAULT false, "requiresAttribution" BOOLEAN NOT NULL DEFAULT true, "requiresSourceLink" BOOLEAN NOT NULL DEFAULT false, "shareAlike" BOOLEAN NOT NULL DEFAULT false, "customTerms" TEXT, "termsUrl" TEXT, "active" BOOLEAN NOT NULL DEFAULT true, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL); CREATE UNIQUE INDEX "CommunityLicensePolicy_key_key" ON "CommunityLicensePolicy"("key");
